    return;

  /* Parse urgency value */
  unsigned char urgency = 3; /* default */
  int incremental = 0;

  /* Try to parse "u=N" format */
  if(priority_str[0] == 'u' && priority_str[1] == '=') {
    char *endptr;
    long val = strtol(priority_str + 2, &endptr, 10);
